    $auditLine = (auditpol /get /subcategory:'MPSSVC Rule-Level Policy Change' 2>&1) | Where-Object { $_ -match 'MPSSVC Rule-Level Policy Change' }
    $val = if ($auditLine) {
        if ($auditLine -match 'Success and Failure') { 'Success and Failure' }
        elseif ($auditLine -match 'Success') { 'Success' }
        elseif ($auditLine -match 'Failure') { 'Failure' }
        else { 'No Auditing' }
    } else { 'Unknown' }
    $status = if ($val -in "Failure","Success and Failure") { 'Pass' } else { 'Fail' }
    $findings.Add((New-Finding `
        -StigId       'WN11-AU-000580' `
        -Title        'Windows 11 must be configured to audit MPSSVC Rule-Level Policy Change Failures.' `
        -Severity     'CAT_II' `
        -Description  'Maintaining an audit trail of system activity logs can help identify configuration errors, troubleshoot service disruptions, and analyze compromises that have occurred, as well as detect attacks. Audi' `
        -Check        "auditpol /get /subcategory:'MPSSVC Rule-Level Policy Change'" `
        -Fix          'auditpol /set /subcategory:'MPSSVC Rule-Level Policy Change' /failure:enable' `
        -PassCriteria 'includes Failure' `
        -Status       $status `
        -Evidence     'MPSSVC Rule-Level Policy Change: ' + $val
    ))
} catch {
    $findings.Add((New-Finding 'WN11-AU-000580' 'Windows 11 must be configured to audit MPSSVC Rule-Level Policy Change Failures.' 'CAT_II' '' '' '' '' 'Error' $_.ToString()))
}
