# WN11-AU-000500
try {
    $val = (Get-ItemProperty -Path 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\EventLog\Application' -Name 'MaxSize' -ErrorAction SilentlyContinue).MaxSize
    $status = if ($null -ne $val -and [int]$val -ge 32768) { 'Pass' } else { 'Fail' }
    $findings.Add((New-Finding `
        -StigId       'WN11-AU-000500' `
        -Title        'The Application event log size must be configured to 32768 KB or greater.' `
        -Severity     'CAT_II' `
        -Description  'Inadequate log size will cause the log to fill up quickly. This may prevent audit events from being recorded properly and require frequent attention by administrative personnel. false</Doc' `
        -Check        'Registry: HKLM:\SOFTWARE\Policies\Microsoft\Windows\EventLog\Application -> MaxSize' `
        -Fix          'If the system is configured to send audit records directly to an audit server, this is NA. This must be documented with the ISSO. Configure the policy value for Computer Configuration >> Administrativ' `
        -PassCriteria 'Value >= 32768' `
        -Status       $status `
        -Evidence     "MaxSize = $(if (`$null -ne `$val) { `$val } else { 'NOT SET' })"
    ))
} catch {
    $findings.Add((New-Finding 'WN11-AU-000500' 'The Application event log size must be configured to 32768 KB or greater.' 'CAT_II' '' '' '' '' 'Error' $_.ToString()))
}
