# WN11-AU-000585
try {
    $val = (Get-ItemProperty -Path 'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Policies\System\Audit' -Name 'ProcessCreationIncludeCmdLine_Enabled' -ErrorAction SilentlyContinue).ProcessCreationIncludeCmdLine_Enabled
    $status = if ($val -eq 1) { 'Pass' } else { 'Fail' }
    $findings.Add((New-Finding `
        -StigId       'WN11-AU-000585' `
        -Title        'Windows 11 must have command line process auditing events enabled for failures.' `
        -Severity     'CAT_II' `
        -Description  'When this policy setting is enabled, the operating system generates audit events when a process fails to start and the name of the program or user that created it. These audit events can assist in und' `
        -Check        'Registry: HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Policies\System\Audit -> ProcessCreationIncludeCmdLine_Enabled' `
        -Fix          'Go to Computer Configuration >> Windows Settings >>Security Settings>> Advanced Audit Policy Configuration >> System Audit Policies >> Detailed Tracking >> Set `"Audit Process Creation`" to `"Failure`' `
        -PassCriteria 'Value = 1' `
        -Status       $status `
        -Evidence     "ProcessCreationIncludeCmdLine_Enabled = $(if (`$null -ne `$val) { `$val } else { 'NOT SET' })"
    ))
} catch {
    $findings.Add((New-Finding 'WN11-AU-000585' 'Windows 11 must have command line process auditing events enabled for failures.' 'CAT_II' '' '' '' '' 'Error' $_.ToString()))
}
return $findings
